            aOrbiterC = (((aWandererC + RotL64(aCross, 29U)) + RotL64(aCarry, 35U)) + 0xFCCB3933A889DAC8ULL) + aPhaseCOrbiterAssignSaltD[(((31U - aIndex) + 15U)) & 31];
            aOrbiterJ = (aWandererH + RotL64(aIngress, 51U)) + 0xE24A6D7B868C0D13ULL;
