            //
            aOrbiterG = (aOrbiterG + aOrbiterH) + 0x242E30CDF3C29E63ULL;
            aOrbiterB = ((aOrbiterB ^ aOrbiterG) ^ 0x74E9CDE5DE166A48ULL) ^ aPhaseCOrbiterUpdateSaltD[((aIndex + 21U)) & 31];
            aOrbiterB = RotL64((aOrbiterB * 0x9C415D46D149F55DULL), 47U);
