            //
            aOrbiterF = (aOrbiterF + aOrbiterA) + 0x3B4BDE41A84D0A86ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterF) ^ 0x2347AC3AC95E6D56ULL;
