            aCross = (RotL64(aExpandLaneB[((S_BLOCK1 - aIndex + 30598U)) & S_BLOCK1], 21U) ^ RotL64(aWorkLaneB[((S_BLOCK1 - aIndex + 28556U)) & S_BLOCK1], 10U));
